import React from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  // Map weather conditions to emoji icons
  const getWeatherEmoji = (cond: string): string => {
    const condLower = cond.toLowerCase();
    if (condLower.includes('sun') || condLower.includes('clear')) return '☀️';
    if (condLower.includes('cloud')) return '☁️';
    if (condLower.includes('rain')) return '🌧️';
    if (condLower.includes('snow')) return '❄️';
    if (condLower.includes('storm') || condLower.includes('thunder')) return '⛈️';
    if (condLower.includes('wind')) return '💨';
    if (condLower.includes('fog') || condLower.includes('mist')) return '🌫️';
    return '🌤️'; // default partly cloudy
  };

  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
      }}
    >
      <Stack direction="vertical" gap={20}>
        {/* Header - City Name */}
        <Text
          variant="h2"
          color="var(--ggui-color-primary-900, #0c4a6e)"
          weight="bold"
        >
          {city}
        </Text>

        {/* Current Weather Section */}
        <Stack direction="horizontal" gap={16} align="center">
          {/* Temperature Display */}
          <div style={{ flex: 1 }}>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-700, #0369a1)',
                lineHeight: 1,
              }}
            >
              {Math.round(temperature)}°{unit}
            </div>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="medium"
              style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
            >
              Feels like the temperature above
            </Text>
          </div>

          {/* Condition Icon */}
          <div
            style={{
              fontSize: '80px',
              textAlign: 'center',
              lineHeight: 1,
            }}
          >
            {getWeatherEmoji(condition)}
          </div>
        </Stack>

        {/* Condition Text */}
        <Text
          variant="h3"
          color="var(--ggui-color-primary-800, #075985)"
          weight="semibold"
          align="center"
        >
          {condition}
        </Text>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-outline, #d4d4d8)',
            margin: 'var(--ggui-spacing-1, 4px) 0',
          }}
        />

        {/* Weather Details - Humidity & Wind Speed */}
        <Row gap={16} justify="between">
          {/* Humidity */}
          <div
            style={{
              flex: 1,
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              textAlign: 'center',
            }}
          >
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="medium"
            >
              HUMIDITY
            </Text>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-2xl, 24px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
                marginTop: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              {Math.round(humidity)}%
            </div>
          </div>

          {/* Wind Speed */}
          <div
            style={{
              flex: 1,
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              textAlign: 'center',
            }}
          >
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="medium"
            >
              WIND SPEED
            </Text>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-2xl, 24px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
                marginTop: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              {Math.round(windSpeed)} {unit === 'F' ? 'mph' : 'km/h'}
            </div>
          </div>
        </Row>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-outline, #d4d4d8)',
            margin: 'var(--ggui-spacing-1, 4px) 0',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>
          <Row gap={4} justify="between" wrap>
            {forecast.map((day, index) => (
              <div
                key={index}
                style={{
                  flex: 1,
                  minWidth: '60px',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: `1px solid var(--ggui-color-outlineVariant, #e4e4e7)`,
                  textAlign: 'center',
                }}
              >
                <Text
                  variant="label"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                  align="center"
                >
                  {day.day}
                </Text>
                <div
                  style={{
                    fontSize: '24px',
                    margin: 'var(--ggui-spacing-1, 4px) 0',
                    textAlign: 'center',
                  }}
                >
                  {day.icon}
                </div>
                <div
                  style={{
                    display: 'flex',
                    gap: 'var(--ggui-spacing-1, 4px)',
                    justifyContent: 'center',
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                  }}
                >
                  <span
                    style={{
                      color: 'var(--ggui-color-primary-600, #0284c7)',
                      fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    }}
                  >
                    {Math.round(day.high)}°
                  </span>
                  <span
                    style={{
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    }}
                  >
                    {Math.round(day.low)}°
                  </span>
                </div>
              </div>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
